INSERT INTO daily_quizzes (date, theme, questions) VALUES ('2026-06-30', 'Mix — Toutes catégories', '[{"question":"Quel pays a la plus grande population au monde en 2024 ?","choices":["Chine","Inde","USA","Indonésie"],"correct":1},{"question":"Qui a composé la \"Symphonie du Nouveau Monde\" ?","choices":["Beethoven","Brahms","Dvořák","Schubert"],"correct":2},{"question":"Quelle est la formule chimique du sel de table ?","choices":["KCl","NaCl","NaF","MgCl2"],"correct":1},{"question":"Dans quel sport Leonardo Da Vinci excellait-il ?","choices":["L''équitation","L''escrime","La lutte","La natation"],"correct":3},{"question":"Combien de touches y a-t-il sur un piano standard ?","choices":["76","88","92","100"],"correct":1},{"question":"Quel est le pays le plus peuplé d''Afrique ?","choices":["Égypte","Congo","Éthiopie","Nigeria"],"correct":3},{"question":"Quel écrivain a créé le personnage de Dracula ?","choices":["Mary Shelley","Edgar Allan Poe","Bram Stoker","H.P. Lovecraft"],"correct":2},{"question":"Quelle couleur obtient-on en mélangeant bleu et jaune ?","choices":["Orange","Violet","Vert","Marron"],"correct":2},{"question":"Quel est le sport le plus pratiqué dans le monde ?","choices":["Basketball","Football","Cricket","Volleyball"],"correct":1},{"question":"En quelle année a eu lieu l''attentat du 11 septembre aux USA ?","choices":["1999","2000","2001","2002"],"correct":2}]'::jsonb) ON CONFLICT (date) DO NOTHING;
